13: type Expander interface {
14: 	SetupExpander(file *ini.File) error
15: 	Expand(string) (string, error)
16: }
17: 
18: type registeredExpander struct {
19: 	name     string
20: 	priority int64
21: 	expander Expander
22: }
23: 
24: var expanders = []registeredExpander{
25: 	{
26: 		name:     "env",
27: 		priority: -10,
28: 		expander: envExpander{},
29: 	},
30: 	{
31: 		name:     "file",
32: 		priority: -5,
33: 		expander: fileExpander{},
34: 	},
35: }
