37: func AddExpander(name string, priority int64, e Expander) {
38: 	expanders = append(expanders, registeredExpander{
39: 		name:     name,
40: 		priority: priority,
41: 		expander: e,
42: 	})
43: }
44: 
45: var regex = regexp.MustCompile(`\$(|__\w+){([^}]+)}`)
46: 
47: // Slightly hacky function to avoid code duplication. If this is eventually called in multiple places, consider refactoring or potentially adding more general helper functions to this package
48: func GetExpanderRegex() *regexp.Regexp {
49: 	return regex
50: }
