81: func ExpandVar(s string) (string, error) {
82: 	for _, expander := range expanders {
83: 		var err error
84: 		s, err = applyExpander(s, expander)
85: 		if err != nil {
86: 			return "", fmt.Errorf("got error while expanding expander %s: %w", expander.name, err)
87: 		}
88: 	}
89: 	return s, nil
90: }
