92: func applyExpander(s string, e registeredExpander) (string, error) {
93: 	matches := regex.FindAllStringSubmatch(s, -1)
94: 
95: 	for _, match := range matches {
96: 		if len(match) < 3 {
97: 			return "", fmt.Errorf("regex error, got %d results back for match, expected 3", len(match))
98: 		}
99: 
100: 		_, isEnv := e.expander.(envExpander)
101: 		if match[1] == "__"+e.name || (match[1] == "" && isEnv) {
102: 			updated, err := e.expander.Expand(match[2])
103: 			if err != nil {
104: 				return "", err
105: 			}
106: 
107: 			s = strings.Replace(s, match[0], updated, 1)
108: 		}
109: 	}
110: 
111: 	return s, nil
112: }
