791: func (cfg *Cfg) readAnnotationSettings() error {
792: 	section := cfg.Raw.Section("annotations")
793: 	cfg.AnnotationCleanupJobBatchSize = section.Key("cleanupjob_batchsize").MustInt64(100)
794: 	cfg.AnnotationMaximumTagsLength = section.Key("tags_length").MustInt64(500)
795: 	switch {
796: 	case cfg.AnnotationMaximumTagsLength > 4096:
797: 		// ensure that the configuration does not exceed the respective column size
798: 		return fmt.Errorf("[annotations.tags_length] configuration exceeds the maximum allowed (4096)")
799: 	case cfg.AnnotationMaximumTagsLength > 500:
800: 		cfg.Logger.Info("[annotations.tags_length] has been increased from its default value; this may affect the performance", "tagLength", cfg.AnnotationMaximumTagsLength)
801: 	case cfg.AnnotationMaximumTagsLength < 500:
802: 		cfg.Logger.Warn("[annotations.tags_length] is too low; the minimum allowed (500) is enforced")
803: 		cfg.AnnotationMaximumTagsLength = 500
804: 	}
805: 
806: 	dashboardAnnotation := cfg.Raw.Section("annotations.dashboard")
807: 	apiIAnnotation := cfg.Raw.Section("annotations.api")
808: 
809: 	newAnnotationCleanupSettings := func(section *ini.Section, maxAgeField string) AnnotationCleanupSettings {
810: 		maxAge, err := gtime.ParseDuration(section.Key(maxAgeField).MustString(""))
811: 		if err != nil {
812: 			maxAge = 0
813: 		}
814: 
815: 		return AnnotationCleanupSettings{
816: 			MaxAge:   maxAge,
817: 			MaxCount: section.Key("max_annotations_to_keep").MustInt64(0),
818: 		}
819: 	}
820: 
821: 	alertingAnnotations := cfg.Raw.Section("unified_alerting.state_history.annotations")
822: 	if alertingAnnotations.Key("max_age").Value() == "" && section.Key("max_annotations_to_keep").Value() == "" {
823: 		// Although this section is not documented anymore, we decided to keep it to avoid potential data-loss when user upgrades Grafana and does not change the setting.
824: 		// TODO delete some time after Grafana 11.
825: 		alertingSection := cfg.Raw.Section("alerting")
826: 		cleanup := newAnnotationCleanupSettings(alertingSection, "max_annotation_age")
827: 		if cleanup.MaxCount > 0 || cleanup.MaxAge > 0 {
828: 			cfg.Logger.Warn("settings 'max_annotations_to_keep' and 'max_annotation_age' in section [alerting] are deprecated. Please use settings 'max_annotations_to_keep' and 'max_age' in section [unified_alerting.state_history.annotations]")
829: 		}
830: 		cfg.AlertingAnnotationCleanupSetting = cleanup
831: 	} else {
832: 		cfg.AlertingAnnotationCleanupSetting = newAnnotationCleanupSettings(alertingAnnotations, "max_age")
833: 	}
834: 
835: 	cfg.DashboardAnnotationCleanupSettings = newAnnotationCleanupSettings(dashboardAnnotation, "max_age")
836: 	cfg.APIAnnotationCleanupSettings = newAnnotationCleanupSettings(apiIAnnotation, "max_age")
837: 
838: 	return nil
839: }
