72: 	// Value returns pair's value.
73: 	Value() string
74: 
75: 	// MustString returns the value's string representation
76: 	// If empty, then it returns the given default.
77: 	MustString(defaultVal string) string
78: 	// MustBool returns the value's boolean representation
79: 	// Otherwise returns the given default.
80: 	MustBool(defaultVal bool) bool
81: 	// MustDuration returns the value's time.Duration
82: 	// representation. Otherwise returns the given default.
