922: func (cfg *Cfg) loadSpecifiedConfigFile(configFile string, masterFile *ini.File) error {
923: 	if configFile == "" {
924: 		configFile = filepath.Join(cfg.HomePath, customInitPath)
925: 		// return without error if custom file does not exist
926: 		if !pathExists(configFile) {
927: 			return nil
928: 		}
929: 	}
930: 
931: 	userConfig, err := ini.Load(configFile)
932: 	if err != nil {
933: 		return fmt.Errorf("failed to parse %q: %w", configFile, err)
934: 	}
935: 
936: 	// micro-optimization since we don't need to share this ini file. In
937: 	// general, prefer to leave this flag as true as it is by default to prevent
938: 	// data races
939: 	userConfig.BlockMode = false
940: 
941: 	for _, section := range userConfig.Sections() {
942: 		for _, key := range section.Keys() {
943: 			if key.Value() == "" {
944: 				continue
945: 			}
946: 
947: 			defaultSec, err := masterFile.GetSection(section.Name())
948: 			if err != nil {
949: 				defaultSec, _ = masterFile.NewSection(section.Name())
950: 			}
951: 			defaultKey, err := defaultSec.GetKey(key.Name())
952: 			if err != nil {
953: 				defaultKey, _ = defaultSec.NewKey(key.Name(), key.Value())
954: 			}
955: 			defaultKey.SetValue(key.Value())
956: 		}
957: 	}
958: 
959: 	cfg.configFiles = append(cfg.configFiles, configFile)
960: 	return nil
